pragma solidity ^0.8.0;

import {BeaconProxy} from "@openzeppelin/contracts/proxy/beacon/BeaconProxy.sol";

// Example of a custom beacon proxy.
// This contract is for testing only, it is not safe for use in production.

contract CustomBeaconProxy is BeaconProxy {
    address private immutable _deployer;
    // The beacon that will be used on calls by the deployer address
    address private immutable _deployerBeacon;

    constructor(address beacon, bytes memory data, address deployerBeacon) payable BeaconProxy(beacon, data) {
        _deployer = msg.sender;
        _deployerBeacon = deployerBeacon;
    }

    function _getBeacon() internal view override returns (address) {
        if (msg.sender == _deployer) return _deployerBeacon;
        return super._getBeacon();
    }
}

import type { Etherscan } from "@nomicfoundation/hardhat-verify/etherscan";
import type { VerifyInfo } from "@nomicfoundation/ignition-core";

export async function verifyEtherscanContract(
  etherscanInstance: Etherscan,
  { address, compilerVersion, sourceCode, name, args }: VerifyInfo
): Promise<
  { type: "success"; contractURL: string } | { type: "failure"; reason: Error }
> {
  try {
    const { message: guid } = await etherscanInstance.verify(
      address,
      sourceCode,
      name,
      compilerVersion,
      args
    );

    const verificationStatus = await etherscanInstance.getVerificationStatus(
      guid
    );

    if (verificationStatus.isSuccess()) {
      const contractURL = etherscanInstance.getContractUrl(address);
      return { type: "success", contractURL };
    } else {
      // todo: what case would cause verification status not to succeed without throwing?
      return { type: "failure", reason: new Error(verificationStatus.message) };
    }
  } catch (e) {
    if (e instanceof Error) {
      return { type: "failure", reason: e };
    } else {
      throw e;
    }
  }
}

import type {
  Artifact,
  ArtifactResolver,
  BuildInfo,
} from "@nomicfoundation/ignition-core";
import type { ArtifactManager } from "hardhat/types/artifacts";

import { readJsonFile } from "@nomicfoundation/hardhat-utils/fs";

export class HardhatArtifactResolver implements ArtifactResolver {
  readonly #artifactManager: ArtifactManager;

  constructor(artifactManager: ArtifactManager) {
    this.#artifactManager = artifactManager;
  }

  public async getBuildInfo(
    contractName: string,
  ): Promise<BuildInfo | undefined> {
    const buildInfoId =
      await this.#artifactManager.getBuildInfoId(contractName);

    if (buildInfoId === undefined) {
      return undefined;
    }

    const buildInfoPath =
      await this.#artifactManager.getBuildInfoPath(buildInfoId);

    if (buildInfoPath === undefined) {
      return undefined;
    }

    return await readJsonFile<BuildInfo>(buildInfoPath);
  }

  public loadArtifact(contractName: string): Promise<Artifact> {
    return this.#artifactManager.readArtifact(contractName);
  }
}

import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
