import path from "node:path";

import { status } from "@nomicfoundation/ignition-core";

import { HardhatArtifactResolver } from "../../helpers/hardhat-artifact-resolver.js";
import { calculateDeploymentStatusDisplay } from "../ui/helpers/calculate-deployment-status-display.js";
import { verifyArtifactsVersion } from "../utils/verifyArtifactsVersion.js";

interface TaskStatusArguments {
  deploymentId: string;
}

const taskStatus: NewTaskActionFunction<TaskStatusArguments> = async (
  { deploymentId },
  hre: HardhatRuntimeEnvironment,
) => {
  const deploymentDir = path.join(
    hre.config.paths.ignition,
    "deployments",
    deploymentId,
  );

  await verifyArtifactsVersion(deploymentDir);

  const artifactResolver = new HardhatArtifactResolver(hre.artifacts);

  const statusResult = await status(deploymentDir, artifactResolver);

  console.log(calculateDeploymentStatusDisplay(deploymentId, statusResult));
};

export default taskStatus;

import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import path from "node:path";

import { trackTransaction } from "@nomicfoundation/ignition-core";

import { verifyArtifactsVersion } from "../utils/verifyArtifactsVersion.js";

interface TrackTxArguments {
  txHash: string;
  deploymentId: string;
}

const taskTransactions: NewTaskActionFunction<TrackTxArguments> = async (
  { txHash, deploymentId },
  hre: HardhatRuntimeEnvironment,
) => {
  const deploymentDir = path.join(
    hre.config.paths.ignition,
    "deployments",
    deploymentId,
  );

  await verifyArtifactsVersion(deploymentDir);

  const connection = await hre.network.create();

  const output = await trackTransaction(
    deploymentDir,
    txHash,
    connection.provider,
    hre.config.ignition.requiredConfirmations,
  );

  console.log(
    output ??
      `Thanks for providing the transaction hash, your deployment has been fixed.

Now you can re-run Hardhat Ignition to continue with your deployment.`,
  );
};

export default taskTransactions;

