import type { EncryptedKeystore } from "../keystores/encryption.js";
import type { FileManager } from "../types.js";

import {
  exists,
  writeJsonFile,
  readJsonFile,
  move,
} from "@nomicfoundation/hardhat-utils/fs";

export class FileManagerImpl implements FileManager {
  public fileExists(absolutePath: string): Promise<boolean> {
    return exists(absolutePath);
  }

  public async writeJsonFile(
    absolutePathToFile: string,
    keystoreFile: EncryptedKeystore,
  ): Promise<void> {
    // First write to a temporary file, then move it to minimize the risk of file corruption
    const tmpPath = `${absolutePathToFile}.tmp`;
    await writeJsonFile(tmpPath, keystoreFile);
    return await move(tmpPath, absolutePathToFile);
  }

  public readJsonFile(absolutePathToFile: string): Promise<EncryptedKeystore> {
    return readJsonFile(absolutePathToFile);
  }
}

import { format } from "../opcodes";
import { TransactionTrace } from "../transaction-trace";
import { Item, TracerDependencies } from "../types";

// TODO make dependencies optional
export async function printConsole(
  txTrace: TransactionTrace,
  dependencies: TracerDependencies
) {
  if (!txTrace.top) {
    throw new Error("[hardhat-tracer]: this.top is undefined in print");
  }
  await printCall(dependencies, 0, txTrace.top);
}

async function printCall(
  dependencies: TracerDependencies,
  depth = 0,
  item: Item<any>
) {
  const indentation = "   ".repeat(depth);

  console.log(indentation + (await format(item, dependencies)));

  if (!!item.children) {
    for (const childItem of item.children) {
      if (!childItem.noFormat) {
        await printCall(dependencies, depth + 1, childItem);
      }
    }
  }
}

